use tonic::{Request, Response, Status};
use user::user_service_server::{UserService, UserServiceServer};

pub struct MyUserService { db: PgPool }

#[tonic::async_trait]
impl UserService for MyUserService {
    async fn get_user(&self, req: Request<GetUserRequest>) -> Result<Response<UserResponse>, Status> {
        let id = req.into_inner().id;
        let user = sqlx::query_as!(User, "SELECT * FROM users WHERE id = $1", id)
            .fetch_optional(&self.db).await
            .map_err(|e| Status::internal(e.to_string()))?
            .ok_or_else(|| Status::not_found("user not found"))?;
        Ok(Response::new(UserResponse { id: user.id, name: user.name, email: user.email }))
    }
}

tonic::transport::Server::builder()
    .add_service(UserServiceServer::new(MyUserService { db }))
    .serve("0.0.0.0:50051".parse()?).await?;

