fn to_status(err: AppError) -> tonic::Status {
    match err {
        AppError::NotFound(msg) => Status::not_found(msg),
        AppError::Validation(msg) => Status::invalid_argument(msg),
        AppError::Unauthorized => Status::unauthenticated("invalid credentials"),
        AppError::Internal(e) => {
            tracing::error!("gRPC internal: {e:?}");
            Status::internal("internal error")
        }
    }
}

