#[tonic::async_trait]
impl UserService for MyUserService {
    type ListUsersStream = ReceiverStream<Result<UserResponse, Status>>;

    async fn list_users(&self, _req: Request<ListUsersRequest>) -> Result<Response<Self::ListUsersStream>, Status> {
        let (tx, rx) = tokio::sync::mpsc::channel(32);
        let db = self.db.clone();

        tokio::spawn(async move {
            let mut rows = sqlx::query_as!(User, "SELECT * FROM users").fetch(&db);
            while let Some(Ok(user)) = rows.next().await {
                if tx.send(Ok(UserResponse::from(user))).await.is_err() { break; }
            }
        });

        Ok(Response::new(ReceiverStream::new(rx)))
    }
}

